import { useState } from "react";
import "./ReactorToggle.css";

function ReactorToggle({
  label = "Reactor System",
  defaultOn = false,
  color = "#00ffae",
}) {
  const [isOn, setIsOn] = useState(defaultOn);

  return (
    <div className="reactor-toggle-wrapper">
      {/* Left Label */}
      <span className={`toggle-label ${isOn ? "active" : ""}`}>
        {label}
      </span>

      {/* Toggle Switch */}
      <div
        className={`reactor-toggle ${isOn ? "active" : ""}`}
        style={{ "--color": color }}
        onClick={() => setIsOn(!isOn)}
      >
        {/* Energy flow layer */}
        <div className="toggle-energy" />

        {/* Glass highlight sweep */}
        <div className="toggle-sweep" />

        {/* Status Text */}
        <span className="toggle-status on-text">ON</span>
        <span className="toggle-status off-text">OFF</span>

        {/* Knob */}
        <div className="toggle-core" />
      </div>
    </div>
  );
}

export default ReactorToggle;

.reactor-toggle-wrapper {
  display: flex;
  align-items: center;
  gap: 20px;
  margin: 25px 0;
  font-family: "Orbitron", sans-serif;
}

/* ========================= */
/* LABEL */
/* ========================= */

.toggle-label {
  font-size: 16px;
  letter-spacing: 1px;
  color: rgba(255,255,255,0.7);
  transition: all 0.3s ease;
}

.toggle-label.active {
  color: var(--color);
  text-shadow: 0 0 10px var(--color);
}

/* ========================= */
/* TOGGLE TRACK */
/* ========================= */

.reactor-toggle {
  position: relative;
  width: 90px;
  height: 40px;
  border-radius: 40px;
  background: rgba(255,255,255,0.05);
  backdrop-filter: blur(12px);
  border: 1px solid rgba(255,255,255,0.1);
  cursor: pointer;
  overflow: hidden;
  transition: all 0.4s ease;
}

/* Active Glow */
.reactor-toggle.active {
  border-color: var(--color);
  box-shadow:
    0 0 20px rgba(0,255,170,0.2),
    inset 0 0 10px rgba(0,0,0,0.6);
}

/* ========================= */
/* ENERGY FLOW */
/* ========================= */

.toggle-energy {
  position: absolute;
  inset: 0;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(255,255,255,0.05),
    transparent
  );
  opacity: 0;
  z-index: 0;
  transition: opacity 0.3s ease;
}

.reactor-toggle.active .toggle-energy {
  opacity: 1;
  animation: energyFlow 2s linear infinite;
}

@keyframes energyFlow {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}

/* ========================= */
/* GLASS SWEEP */
/* ========================= */

.toggle-sweep {
  position: absolute;
  inset: 0;
  background: linear-gradient(
    120deg,
    transparent 20%,
    rgba(255,255,255,0.25),
    transparent 80%
  );
  transform: translateX(-100%);
  z-index: 0;
}

.reactor-toggle.active .toggle-sweep {
  animation: sweepMove 3s ease-in-out infinite;
}

@keyframes sweepMove {
  0% { transform: translateX(-100%); }
  50% { transform: translateX(120%); }
  100% { transform: translateX(120%); }
}

/* ========================= */
/* STATUS TEXT */
/* ========================= */

.toggle-status {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  font-size: 11px;
  letter-spacing: 1.5px;
  font-weight: 600;
  pointer-events: none;
  transition:
    opacity 0.3s ease,
    color 0.4s ease,
    text-shadow 0.5s ease;
  z-index: 1;
}

/* Bring text closer to knob */
.on-text {
  left: 10px; /* reduced from 14px */
  color: var(--color);
  opacity: 0;
  text-shadow: 0 0 0px transparent;
}

.off-text {
  right: 10px; /* reduced from 14px */
  color: rgba(255,255,255,0.55);
  opacity: 1;
  text-shadow: 0 0 0px transparent;
}

/* Active State */
.reactor-toggle.active .on-text {
  opacity: 1;
  transition-delay: 0.15s; /* glow ramps after knob starts moving */
  text-shadow:
    0 0 4px var(--color),
    0 0 8px var(--color),
    0 0 14px rgba(0,255,170,0.2);
}

.reactor-toggle.active .off-text {
  opacity: 0;
  transition-delay: 0s;
}

/* ========================= */
/* DISTORTION + BLUR LENS */
/* ========================= */

.reactor-toggle::after {
  content: "";
  position: absolute;
  top: 4px;
  left: 4px;
  width: 32px;
  height: 32px;
  border-radius: 50%;
  backdrop-filter: blur(6px) saturate(140%);
  background: rgba(255,255,255,0.08);
  box-shadow:
    inset 0 0 8px rgba(255,255,255,0.2),
    inset 0 0 14px rgba(255,255,255,0.15);
  z-index: 2;
  pointer-events: none;
  transition: transform 0.4s cubic-bezier(.34,1.56,.64,1);
}

.reactor-toggle.active::after {
  transform: translateX(50px);
}

/* ========================= */
/* KNOB */
/* ========================= */

.toggle-core {
  position: absolute;
  top: 4px;
  left: 4px;
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: radial-gradient(circle at 30% 30%, #ffffff, #bdbdbd);
  box-shadow:
    0 4px 10px rgba(0,0,0,0.5),
    inset 0 2px 6px rgba(255,255,255,0.4);
  transition: all 0.4s cubic-bezier(.34,1.56,.64,1);
  z-index: 3;
}

.reactor-toggle.active .toggle-core {
  transform: translateX(50px);
  background: radial-gradient(circle at 30% 30%, var(--color), #006b4a);
  box-shadow:
    0 0 15px var(--color),
    0 4px 10px rgba(0,0,0,0.6);
}
